class Solution(object):
    def uniqueXorTriplets(self, nums):
        n = len(nums)
        # Compute all unique pairwise XORs nums[j] ^ nums[k] for j <= k
        pair_xors = set()
        for j in range(n):
            for k in range(j, n):
                pair_xors.add(nums[j] ^ nums[k])

        # For each element nums[i], XOR it with all pair XORs
        result = set()
        for x in nums:
            for p in pair_xors:
                result.add(x ^ p)

        return len(result)
